mapper.select:
SELECT
    d.id, d.line_no, d.divide_name, d.divide_no, d.access_strategy_no, d.risk_strategy_no, d.version, d.deploy_at, d.is_valid, d.is_delete,
    dp.product_no, dp.type
FROM divide d
LEFT JOIN divide_product dp ON d.divide_no = dp.divide_no


        d.line_no = #{param.lineNo}


        AND d.divide_name like CONCAT(#{param.divideName}, '%')


        AND d.divide_no = #{param.divideNo}


        AND d.is_valid = #{param.isValid}

    AND d.is_delete = 0 AND dp.is_delete = 0

LIMIT #{start}, #{limit}

SELECT COUNT(*)
FROM divide d
LEFT JOIN divide_product dp ON d.divide_no = dp.divide_no


        d.line_no = #{param.lineNo}


        AND d.divide_name like CONCAT(#{param.divideName}, '%')


        AND d.divide_no = #{param.divideNo}


        AND d.is_valid = #{param.isValid}

    AND d.is_delete = 0 AND dp.is_delete = 0
